package io.camunda.connector.barcode;

/* ******************************************************************** */
/*                                                                      */
/*  BarcodeFunction                                                         */
/*                                                                      */
/*  This connector is the main connector, doing the distribution on     */
/*  specific function                                                   */
/* ******************************************************************** */

import com.google.zxing.BarcodeFormat;
import com.google.zxing.MultiFormatWriter;
import com.google.zxing.common.BitMatrix;
import io.camunda.connector.api.annotation.OutboundConnector;
import io.camunda.connector.api.error.ConnectorException;
import io.camunda.connector.api.outbound.OutboundConnectorContext;
import io.camunda.connector.api.outbound.OutboundConnectorFunction;
import io.camunda.connector.cherrytemplate.CherryConnector;
import io.camunda.filestorage.FileRepoFactory;
import io.camunda.filestorage.FileVariable;
import io.camunda.filestorage.FileVariableReference;
import io.camunda.filestorage.storage.StorageDefinition;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.ByteArrayOutputStream;
import java.util.*;

import com.google.zxing.client.j2se.MatrixToImageWriter;




@OutboundConnector(name = "BarcodeFunction", inputVariables = {BarcodeInput.BARCODE_FORMAT,
        BarcodeInput.CODE,
        BarcodeInput.OUTPUT_FORMAT,
        BarcodeInput.WIDTH,
        BarcodeInput.HEIGHT,
        BarcodeInput.DESTINATION_FILE_NAME,
        BarcodeInput.DESTINATION_JSONSTORAGEDEFINITION,
    }, type = "c-barcode-function")

public class BarcodeFunction implements OutboundConnectorFunction, CherryConnector {

    private static final String WORKER_LOGO =
             "data:image/png;base64,";


    private final Logger logger = LoggerFactory.getLogger(BarcodeFunction.class.getName());

    @Override
    public BarcodeOutput execute(OutboundConnectorContext outboundConnectorContext) throws Exception {
        BarcodeInput barcodeInput;
        try {
            barcodeInput = outboundConnectorContext.bindVariables(BarcodeInput.class);
        } catch (Exception e) {
            throw new ConnectorException(BarcodeError.ERROR_BAD_INPUTPARAMETER, "PDFFunction can't bind variable " + e.getMessage() + "]");
        }
        long beginTime = System.currentTimeMillis();

        String code = barcodeInput.getCode();
        String formatOutput = barcodeInput.getOutputFormat();
        BarcodeFormat barcodeFormat = BarcodeFormat.valueOf(barcodeInput.getBarcodeFormat());
        logger.info("BarcodeFunction receive code [{}], format[{}]", code, barcodeFormat);

        ByteArrayOutputStream outputStream = new ByteArrayOutputStream();
        try {
            final BitMatrix bitMatrix = new MultiFormatWriter().encode(code, barcodeFormat,
                    barcodeInput.getDefaultWidth(), barcodeInput.getDefaultHeight());

            MatrixToImageWriter.writeToStream(bitMatrix, formatOutput, outputStream);
        } catch (Exception e) {
            logger.error("During generation operation : ", e);
            throw new ConnectorException(BarcodeError.GENERATION_ERROR, "Error " + e);
        }

        StorageDefinition destinationStorageDefinition = barcodeInput.getDestinationStorageDefinitionObject();

        if (destinationStorageDefinition == null) {
            // no storage: this is a problem
            logger.error("No destination storage definition define ");
            throw new ConnectorException(BarcodeError.NO_DESTINATION_STORAGE_DEFINITION_DEFINE);
        }

        FileRepoFactory fileRepoFactory = FileRepoFactory.getInstance();
        BarcodeOutput barcodeOutput = new BarcodeOutput();

        try {
            FileVariable fileVariableOut = new FileVariable();

            fileVariableOut.setValue(outputStream.toByteArray());
            fileVariableOut.setName(barcodeInput.getDestinationFileName());
            fileVariableOut.setMimeType(mimeTypeFromOutputFormat(barcodeInput.getOutputFormat()));
            fileVariableOut.setStorageDefinition(destinationStorageDefinition);


            FileVariableReference outputFileReference = fileRepoFactory.saveFileVariable(fileVariableOut, outboundConnectorContext);
            barcodeOutput.destinationFile = outputFileReference;

            logger.info("Generates code[" + code + "] imageFormat[" + barcodeFormat + "] in {} ms", System.currentTimeMillis() - beginTime);

            return barcodeOutput;
        } catch (Exception e) {
            logger.error("During operation : ", e);
            throw new ConnectorException(BarcodeError.SAVE_OPERATION, "Error " + e);

        }


    }

    private String mimeTypeFromOutputFormat(String outputFormat) {
        if (outputFormat == null) return "image/png";
        return switch (outputFormat) {
            case BarcodeInput.OUTPUT_FORMAT_JPEG -> "image/jpeg";
            case BarcodeInput.OUTPUT_FORMAT_BMP -> "image/bmp";
            case BarcodeInput.OUTPUT_FORMAT_GIF -> "image/gif";
            case BarcodeInput.OUTPUT_FORMAT_WBPM -> "image/vnd.wap.wbmp";
            default -> "image/png"; // PNG and unknown formats
        };
    }

    @Override
    public String getDescription() {
        return "Generate a barcode from a code and a barcode format";
    }

    @Override
    public String getLogo() {
        return WORKER_LOGO;
    }

    @Override
    public String getCollectionName() {
        return "";
    }

    @Override
    public Map<String, String> getListBpmnErrors() {
        Map<String, String> allErrors = new HashMap<>();

        allErrors.put(BarcodeError.ERROR_BAD_INPUTPARAMETER, BarcodeError.ERROR_BAD_INPUTPARAMETER_EXPLANATION);
        allErrors.put(BarcodeError.ERROR_BAD_INPUTPARAMETER, BarcodeError.ERROR_BAD_INPUTPARAMETER_EXPLANATION);
        allErrors.put(BarcodeError.INCORRECT_STORAGEDEFINITION,BarcodeError.INCORRECT_STORAGEDEFINITION_EXPLANATION);
        allErrors.put(BarcodeError.SAVE_OPERATION,BarcodeError.SAVE_OPERATION_EXPLANATION);
        allErrors.put(BarcodeError.GENERATION_ERROR,BarcodeError.GENERATION_ERROR_EXPLANATION);
        allErrors.put(BarcodeError.NO_DESTINATION_STORAGE_DEFINITION_DEFINE, BarcodeError.NO_DESTINATION_STORAGE_DEFINITION_DEFINE_EXPLANATION);

        return allErrors;
    }

    @Override
    public Class<?> getInputParameterClass() {
        return BarcodeInput.class;
    }

    @Override
    public Class<?> getOutputParameterClass() {
        return BarcodeOutput.class;
    }

    /**
     * Only task at this moment (no InboundConnector)
     *
     * @return list of items where the function applies
     */
    @Override
    public List<String> getAppliesTo() {
        return List.of("bpmn:ServiceTask");
    }


}
